// .storybook/preview.ts — one decorator per concern
const withTheme = (Story, context) => (
  <ThemeProvider theme={context.globals.theme}><Story /></ThemeProvider>
);

const withReactQuery = (Story) => (
  <QueryClientProvider client={queryClient}><Story /></QueryClientProvider>
);

const preview: Preview = {
  decorators: [withTheme, withReactQuery],
};

import type { Meta, StoryObj } from '@storybook/react';
import { fn } from '@storybook/test';
import { Button } from './Button';

const meta = {
  title: 'Components/Button',
  component: Button,
  tags: ['autodocs'],
  argTypes: {
    variant: { control: 'select', options: ['primary', 'secondary', 'danger'] },
    disabled: { control: 'boolean' },
    onClick: { action: 'clicked' },
  },
  args: { onClick: fn() },
} satisfies Meta<typeof Button>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Primary: Story = { args: { variant: 'primary', children: 'Click me' } };
export const Danger: Story = { args: { variant: 'danger', children: 'Delete' } };

import { within, userEvent, expect } from '@storybook/test';

export const ClickInteraction: Story = {
  args: { children: 'Click Me' },
  play: async ({ canvasElement, args }) => {
    const canvas = within(canvasElement);
    await userEvent.click(canvas.getByRole('button'));
    await expect(args.onClick).toHaveBeenCalled();
  },
};

// scripts/derive-variants.ts
// Emits a list of variant names from a TS union type via the TS compiler API.
import { Project, SyntaxKind } from "ts-morph";
const project = new Project();
const sf = project.addSourceFileAtPath(process.argv[2]);
const iface = sf.getInterfaceOrThrow("ButtonProps");
for (const prop of iface.getProperties()) {
  const type = prop.getType();
  if (type.isUnion()) {
    const names = type.getUnionTypes().map((t) => t.getText());
    console.log(`${prop.getName()}: ${names.join(", ")}`);
  }
}
